blocks.body:
{
    "level": "B2",
    "intro": "W tym temacie nauczysz się <strong>złożonych konstrukcji biernych z bezokolicznikami i gerundami</strong>. Są to kluczowe formy pisania akademickiego, naukowego i formalnego.",
    "rules": [
        {
            "label": "do zrobienia",
            "color": "emerald",
            "text": "<strong>Bezokolicznik bierny</strong> – teraźniejszość/przyszłość:",
            "example": "The report needs to be finished."
        },
        {
            "label": "jest zrobione",
            "color": "blue",
            "text": "<strong>Gerund bierny</strong> to proces:",
            "example": "She hates being interrupted."
        },
        {
            "label": "zostało zrobione",
            "color": "rose",
            "text": "<strong>Doskonały pasywny gerund</strong> - poprzednia akcja:",
            "example": "Having been warned, he was careful."
        }
    ]
}

{
    "title": "1. Trzy podstawowe formy pasywne",
    "intro": "Porównanie trzech kluczowych projektów:",
    "items": [
        {
            "label": "być + V3",
            "title": "Bezokolicznik bierny",
            "subtitle": "Akcja teraźniejsza/przyszła w stronie biernej"
        },
        {
            "label": "być + V3",
            "title": "Doskonały bezokolicznik bierny",
            "subtitle": "Poprzednia czynność została ukończona przed mówieniem"
        },
        {
            "label": "będąc + V3",
            "title": "Pasywny gerund",
            "subtitle": "Proces, ciągłe działanie w stronie biernej"
        },
        {
            "label": "będąc + V3",
            "title": "Idealny pasywny gerund",
            "subtitle": "Akcja, która poprzedzała inną"
        }
    ]
}

{
    "title": "2. Do zrobienia to bezokolicznik bierny",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "<strong>być + imiesłów czasu przeszłego (V3)</strong>. Używane po wielu czasownikach i w konstrukcjach modalnych.",
            "examples": [
                {
                    "en": "The report needs to be finished by Friday.",
                    "ua": "Raport musi być gotowy do piątku."
                },
                {
                    "en": "I want to be informed immediately.",
                    "ua": "Chcę zostać natychmiast powiadomiony."
                },
                {
                    "en": "This task has to be completed today.",
                    "ua": "To zadanie musi zostać wykonane dzisiaj."
                }
            ]
        },
        {
            "label": "Po pojawieniu się czasowników pojawiają się",
            "color": "sky",
            "description": "Po <strong>wydaje się, pojawia się, zdarza się, okazuje się</strong>.",
            "examples": [
                {
                    "en": "He appears to be well respected.",
                    "ua": "Wydaje się, że budzi szacunek."
                },
                {
                    "en": "The meeting seems to be postponed.",
                    "ua": "Wygląda na to, że spotkanie zostało przełożone."
                },
                {
                    "en": "She happened to be chosen for the role.",
                    "ua": "Tak się złożyło, że została wybrana do tej roli."
                }
            ]
        },
        {
            "label": "Po chcieć, oczekiwać, chcieć",
            "color": "amber",
            "description": "Gdy ktoś chce, żeby <strong>coś zostało zrobione</strong>.",
            "examples": [
                {
                    "en": "I want this issue to be resolved.",
                    "ua": "Chcę, żeby ten problem został rozwiązany."
                },
                {
                    "en": "They expect the project to be approved.",
                    "ua": "Oczekują, że projekt zostanie zatwierdzony."
                },
                {
                    "en": "We would like the order to be delivered.",
                    "ua": "Chcielibyśmy, żeby zamówienie zostało zrealizowane."
                }
            ]
        }
    ]
}

{
    "title": "3. To have made to doskonały bezokolicznik strony biernej",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "<strong>być + V3</strong>. Wskazuje czynność, która <strong>zdarzyła się wcześniej</strong> w odniesieniu do momentu wypowiedzi.",
            "examples": [
                {
                    "en": "He seems to have been promoted.",
                    "ua": "Wygląda na to, że dostał awans."
                },
                {
                    "en": "The documents appear to have been lost.",
                    "ua": "Wygląda na to, że dokumenty zaginęły."
                },
                {
                    "en": "She claims to have been invited.",
                    "ua": "Twierdzi, że została zaproszona."
                }
            ]
        },
        {
            "label": "Struktury raportowania",
            "color": "sky",
            "description": "W bezosobowych konstrukcjach pasywnych dla <strong>założeń na temat przeszłości</strong>.",
            "examples": [
                {
                    "en": "He is believed to have been kidnapped.",
                    "ua": "Uważa się, że został porwany."
                },
                {
                    "en": "The painting is thought to have been stolen.",
                    "ua": "Uważa się, że obraz został skradziony."
                },
                {
                    "en": "She is reported to have been seen in Paris.",
                    "ua": "Według doniesień widziano ją w Paryżu."
                }
            ]
        },
        {
            "label": "Po modach + mieć",
            "color": "amber",
            "description": "Po <strong>muszę, mogłem, powinienem mieć</strong> - założenia dotyczące przeszłości.",
            "examples": [
                {
                    "en": "The email must have been sent.",
                    "ua": "E-mail musiał zostać wysłany."
                },
                {
                    "en": "The mistake could have been avoided.",
                    "ua": "Można było uniknąć błędów."
                },
                {
                    "en": "This should have been done earlier.",
                    "ua": "Trzeba było to zrobić wcześniej."
                }
            ]
        }
    ]
}

{
    "title": "4. Bycie skończonym jest biernym gerundem",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "<strong>bycie + V3</strong>. Używane po przyimkach i czasownikach wymagających gerunda.",
            "examples": [
                {
                    "en": "She hates being interrupted.",
                    "ua": "Nienawidzi, gdy jej przeszkadzano."
                },
                {
                    "en": "I remember being taught this rule.",
                    "ua": "Pamiętam, że uczono mnie tej zasady."
                },
                {
                    "en": "He denied being involved in the incident.",
                    "ua": "Zaprzeczył swojemu udziałowi w zdarzeniu."
                }
            ]
        },
        {
            "label": "Po przyimkach",
            "color": "sky",
            "description": "Після <strong>bez, po, przed, obok, pomimo</strong>.",
            "examples": [
                {
                    "en": "He left without being noticed.",
                    "ua": "Pozostawił niezauważony."
                },
                {
                    "en": "After being rejected, she tried again.",
                    "ua": "Po odrzuceniu próbowała ponownie."
                },
                {
                    "en": "Despite being warned, he continued.",
                    "ua": "Pomimo ostrzeżenia kontynuował."
                }
            ]
        },
        {
            "label": "Po polubieniu ciesz się, unikaj",
            "color": "amber",
            "description": "Po czasownikach wymagających <strong>form -ing</strong>.",
            "examples": [
                {
                    "en": "Nobody likes being criticized.",
                    "ua": "Nikt nie lubi być krytykowany."
                },
                {
                    "en": "He enjoys being praised.",
                    "ua": "Lubi być chwalony."
                },
                {
                    "en": "She avoids being seen in public.",
                    "ua": "Unika rozgłosu."
                }
            ]
        }
    ]
}

{
    "title": "5. Wykonanie jest doskonałym biernym gerundem",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "<strong>byłem + V3</strong>. Dla działań, które <strong>poprzedziły inne</strong> (przyczyna → skutek).",
            "examples": [
                {
                    "en": "Having been warned, he was more careful.",
                    "ua": "Otrzymawszy ostrzeżenie, był bardziej ostrożny."
                },
                {
                    "en": "Having been told the truth, she felt relieved.",
                    "ua": "Gdy poznała prawdę, poczuła ulgę."
                },
                {
                    "en": "Having been approved, the project will begin.",
                    "ua": "Po akceptacji projekt zostanie rozpoczęty."
                }
            ]
        },
        {
            "label": "Styl formalny",
            "color": "sky",
            "description": "Często w <strong>przemówieniach akademickich, oficjalnych</strong> i pisemnych.",
            "examples": [
                {
                    "en": "Having been elected, she took office.",
                    "ua": "Po wyborach objęła urząd."
                },
                {
                    "en": "Having been reviewed, the document was signed.",
                    "ua": "Po zapoznaniu się z dokumentem podpisali go."
                },
                {
                    "en": "Having been trained properly, the team succeeded.",
                    "ua": "Dzięki odpowiedniemu szkoleniu zespół odniósł sukces."
                }
            ]
        },
        {
            "label": "Po czasownikach pamięci",
            "color": "amber",
            "description": "Potem <strong>pamiętaj, żałuj, zaprzeczaj, przyznaj się</strong>.",
            "examples": [
                {
                    "en": "She regrets having been so rude.",
                    "ua": "Żałuje, że była taka niegrzeczna."
                },
                {
                    "en": "He admits having been mistaken.",
                    "ua": "Przyznaje, że się mylił."
                },
                {
                    "en": "I remember having been told about this.",
                    "ua": "Pamiętam, że mi o tym powiedziano."
                }
            ]
        }
    ]
}

{
    "title": "6. Najczęstsze wzorce używania",
    "sections": [
        {
            "label": "Potrzebuję/chcę/wymagam + do zrobienia",
            "color": "emerald",
            "description": "<strong>Potrzebujesz/chcesz/wymagasz + być + V3</strong> – potrzeba działania.",
            "examples": [
                {
                    "en": "This problem needs to be solved.",
                    "ua": "Ten problem wymaga rozwiązania."
                },
                {
                    "en": "The contract needs to be signed.",
                    "ua": "Należy podpisać umowę."
                },
                {
                    "en": "The issue requires to be addressed.",
                    "ua": "Ten problem wymaga rozwiązania."
                }
            ]
        },
        {
            "label": "wydaje się/wydaje się + do zrobienia",
            "color": "blue",
            "description": "<strong>Wydaje się/wygląda na + V3</strong> — wrażenie, przypuszczenie.",
            "examples": [
                {
                    "en": "The door seems to be locked.",
                    "ua": "Wygląda na to, że drzwi są zamknięte."
                },
                {
                    "en": "He appears to be respected by everyone.",
                    "ua": "Wygląda na to, że wszyscy go szanują."
                }
            ]
        },
        {
            "label": "się mówi/uważa + jest/było",
            "color": "sky",
            "description": "<strong>Raportowanie bierne</strong> — raporty, plotki.",
            "examples": [
                {
                    "en": "He is said to be a genius.",
                    "ua": "Mówią, że jest geniuszem."
                },
                {
                    "en": "She is believed to have left the country.",
                    "ua": "Uważa się, że opuściła kraj."
                }
            ]
        },
        {
            "label": "nienawidzę/lubię/cieszę się + bycie skończonym",
            "color": "amber",
            "description": "<strong>Czasowniki odczuwające + bycie + V3</strong> — reakcja na czynność.",
            "examples": [
                {
                    "en": "She hates being ignored.",
                    "ua": "Nienawidzi być ignorowana."
                },
                {
                    "en": "Children love being praised.",
                    "ua": "Dzieci uwielbiają być chwalone."
                }
            ]
        }
    ]
}

{
    "title": "7. Tabela zbiorcza formularzy",
    "intro": "Porównanie wszystkich form biernych z bezokolicznikami i gerundami:",
    "rows": [
        {
            "en": "to be + V3",
            "ua": "Bezokolicznik bierny",
            "note": "The work needs to be done."
        },
        {
            "en": "to have been + V3",
            "ua": "Doskonały bezokolicznik bierny",
            "note": "He seems to have been promoted."
        },
        {
            "en": "being + V3",
            "ua": "Pasywny gerund",
            "note": "She hates being interrupted."
        },
        {
            "en": "having been + V3",
            "ua": "Idealny pasywny gerund",
            "note": "Having been warned, he left."
        }
    ],
    "warning": "📌 <strong>Formy doskonałe</strong> (być, być) wskazują na czynność, która poprzedzała inną!"
}

{
    "title": "8. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Zamieszanie, które należy zrobić i które jest robione.",
            "wrong": "I enjoy to be praised.",
            "right": "✅ I enjoy being praised."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Skip był w doskonałej formie.",
            "wrong": "He seems to have promoted.",
            "right": "✅ He seems to have been promoted."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Nieprawidłowa kolejność słów.",
            "wrong": "Having warned been, he was careful.",
            "right": "✅ Having been warned, he was careful."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Forma aktywna zamiast pasywnej.",
            "wrong": "The report needs finishing.",
            "right": "✅ The report needs to be finished."
        }
    ]
}
